section.codeblock:
/* Brand colors */
:root {
  --brand-primary: #1a3a5c;
  --brand-accent: #e8721c;
}

/* Page header */
header.brand-header {
  background: var(--brand-primary);
  color: white;
  padding: 1rem 2rem;
}

/* Topic titles */
.topictitle1 {
  color: var(--brand-primary);
  border-bottom: 3px solid var(--brand-accent);
}

/* Code blocks */
pre.codeblock {
  background: #f4f4f4;
  border-left: 4px solid var(--brand-accent);
  padding: 1rem;
}

/* Navigation sidebar */
nav[role="toc"] {
  background: #f9f9f9;
  border-right: 1px solid #ddd;
}
